"use client";

import { useEffect, useState } from "react";
import "./memberAdmin.css";

export default function UserManagementPage() {
  const [users, setUsers] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // 임시 데이터 (나중에 API 연결)
  useEffect(() => {
     fetch('http://localhost:8080/api/admin/member')
    setIsLoading(false);
  }, []);

  const handleDeleteUser = (id: number) => {
    if (confirm("정말 이 회원을 탈퇴 처리하시겠습니까?")) {
      // 삭제 API 호출 로직 추가 예정
      setUsers(users.filter(u => u.id !== id));
      alert("삭제되었습니다.");
    }
  };

  if (isLoading) return <div>로딩 중...</div>;

  return (
    <div>
      <div className="admin-search-bar">
        <h1 className="admin-title" style={{ borderBottom: 'none', marginBottom: 0 }}>회원 관리</h1>
        <input 
          type="text" 
          placeholder="이메일 또는 닉네임 검색" 
          className="admin-search-input" 
        />
      </div>

      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>이메일</th>
            <th>닉네임</th>
            <th>권한</th>
            <th>가입일</th>
            <th>관리</th>
          </tr>
        </thead>
        <tbody>
          {users.map((user) => (
            <tr key={user.id}>
              <td>{user.id}</td>
              <td>{user.email}</td>
              <td>{user.nickname}</td>
              <td>
                <span className={`badge ${user.role === 'ADMIN' ? 'badge-admin' : 'badge-user'}`}>
                  {user.role}
                </span>
              </td>
              <td>{user.createdAt}</td>
              <td>
                <button 
                  onClick={() => handleDeleteUser(user.id)}
                  style={{ color: '#e74a3b', border: 'none', background: 'none', cursor: 'pointer', fontWeight: 'bold' }}
                >
                  강제탈퇴
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}